import React, { useState } from 'react';
import axios from 'axios';

function OrderForm() {
  const [service, setService] = useState('iPhone 17 Pro Max iCloud Unlock Clean/Lost');
  const [imei, setImei] = useState('');
  const [email, setEmail] = useState('');
  const [success, setSuccess] = useState(false);
  const [orderId, setOrderId] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    try {
      const res = await axios.post('http://localhost:5000/api/orders', { service, imei, email });
      setSuccess(true);
      setOrderId(res.data.order.orderId);
    } catch (err) {
      setError('وقع مشكل أثناء إرسال الطلب.');
    }
  };

  if (success) {
    return (
      <div style={{textAlign: 'center'}}>
        <h3>تم إرسال الطلب بنجاح!</h3>
        <p>رقم الطلب: <b>{orderId}</b></p>
        <p>يمكنك تتبع حالة الطلب من لوحة التتبع.</p>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} style={{maxWidth: 400, margin: 'auto', background: '#fff', padding: 24, borderRadius: 8}}>
      <h3>طلب إزالة iCloud</h3>
      <label>نوع الخدمة:</label>
      <select value={service} onChange={e => setService(e.target.value)} required>
        <option value="iPhone 17 Pro Max iCloud Unlock Clean/Lost">iPhone 17 Pro Max iCloud Unlock Clean/Lost</option>
        <option value="iPhone 15 iCloud Unlock">iPhone 15 iCloud Unlock</option>
        <option value="iPad iCloud Unlock">iPad iCloud Unlock</option>
      </select>
      <label>IMEI:</label>
      <input type="text" value={imei} onChange={e => setImei(e.target.value)} required maxLength={16} pattern="[A-Za-z0-9]+" />
      <label>الإيميل:</label>
      <input type="email" value={email} onChange={e => setEmail(e.target.value)} required />
      <button type="submit" style={{marginTop: 12, background: '#1abc4c', color: '#fff', border: 'none', padding: 10, borderRadius: 6}}>إرسال الطلب</button>
      {error && <p style={{color: 'red'}}>{error}</p>}
    </form>
  );
}

export default OrderForm;
